from collections import defaultdict

SEVERITY_SCORE = {
    SignalSeverity.INFO:     0,
    SignalSeverity.LOW:      1,
    SignalSeverity.MODERATE: 2,
    SignalSeverity.HIGH:     4,
    SignalSeverity.CRITICAL: 8,
}

class SignalAggregator:
    """
    Collects signals from all monitors and produces a per-vendor risk delta.
    If a vendor's aggregate score crosses a threshold, triggers an alert.
    """
    THRESHOLDS = {
        "re_assess": 6,   # aggregate score that triggers an unscheduled re-assessment
        "escalate":  12,  # triggers tier escalation review
        "exit":      20,  # triggers exit-plan initiation
    }

    def aggregate(self, signals: list[MonitoringSignal]
                  ) -> dict[str, dict]:
        by_vendor: dict[str, list[MonitoringSignal]] = defaultdict(list)
        for s in signals:
            by_vendor[s.vendor_id].append(s)

        results = {}
        for vendor_id, vsignals in by_vendor.items():
            score = sum(SEVERITY_SCORE[s.severity] for s in vsignals)
            action = "log"
            if score >= self.THRESHOLDS["exit"]:
                action = "exit"
            elif score >= self.THRESHOLDS["escalate"]:
                action = "escalate"
            elif score >= self.THRESHOLDS["re_assess"]:
                action = "re_assess"

            results[vendor_id] = {
                "aggregate_score": score,
                "recommended_action": action,
                "signals": vsignals,
                "critical_count": sum(1 for s in vsignals
                                      if s.severity == SignalSeverity.CRITICAL),
            }
        return results

def route_alert(vendor_id: str, result: dict, notify_fn) -> None:
    action = result["recommended_action"]
    score  = result["aggregate_score"]
    crits  = result["critical_count"]

    if action == "log":
        return  # dashboard only

    message = (
        f"Vendor {vendor_id} | Score {score} | {crits} CRITICAL signal(s)\n"
        + "\n".join(f"  [{s.severity.value}] {s.title}" for s in result["signals"]
                    if s.is_actionable())
    )

    if action == "exit":
        notify_fn(channel="#tprm-critical", message=message, pagerduty=True)
    elif action == "escalate":
        notify_fn(channel="#tprm-high", message=message, pagerduty=False)
    elif action == "re_assess":
        notify_fn(channel="#tprm-moderate", message=message, pagerduty=False)

from difflib import SequenceMatcher

def canary_regression_check(
    canonical_pairs: list[tuple[str, str]],   # (prompt, expected_response)
    new_responses:   list[str],
    similarity_threshold: float = 0.75,
) -> list[dict]:
    """Flag pairs where the new response diverges significantly from expected."""
    regressions = []
    for (prompt, expected), actual in zip(canonical_pairs, new_responses):
        ratio = SequenceMatcher(None, expected, actual).ratio()
        if ratio < similarity_threshold:
            regressions.append({
                "prompt": prompt,
                "expected_snippet": expected[:120],
                "actual_snippet":   actual[:120],
                "similarity": ratio,
            })
    return regressions
